import java.util.LinkedList

fun queueOps(arr: IntArray): Int {
    if (arr.isEmpty()) return 0
    val queue = LinkedList<Int>()
    val opCount = arr[0]
    var idx = 1; var total = 0
    for (i in 0 until opCount) {
        val type = arr[idx]; val v = arr[idx + 1]; idx += 2
        if (type == 1) queue.add(v)
        else if (type == 2 && queue.isNotEmpty()) total += queue.poll()
    }
    return total
}

from collections import deque

def queue_ops(arr: list[int]) -> int:
    if not arr:
        return 0
    q: deque[int] = deque()
    op_count = arr[0]
    idx = 1
    total = 0
    for _ in range(op_count):
        op_type = arr[idx]
        val = arr[idx + 1]
        idx += 2
        if op_type == 1:
            q.append(val)
        elif op_type == 2:
            if q:
                total += q.popleft()
    return total

use std::collections::VecDeque;

pub fn queue_ops(arr: &[i32]) -> i32 {
    if arr.is_empty() { return 0; }
    let mut queue: VecDeque<i32> = VecDeque::new();
    let op_count = arr[0] as usize;
    let mut idx = 1;
    let mut total: i32 = 0;
    for _ in 0..op_count {
        let t = arr[idx];
        let v = arr[idx + 1];
        idx += 2;
        if t == 1 { queue.push_back(v); }
        else if t == 2 {
            if let Some(val) = queue.pop_front() { total += val; }
        }
    }
    total
}

object QueueOperations {

